mapper.select:
SELECT r.id, r.user_id, r.metric_type, r.metric_value, r.unit, r.record_date, r.measured_at, r.created_at, r.updated_at FROM body_metric_record r WHERE r.user_id = #{userId} AND r.metric_type = #{metricType} AND NOT EXISTS ( SELECT 1 FROM body_metric_record newer WHERE newer.user_id = r.user_id AND newer.metric_type = r.metric_type AND newer.record_date = r.record_date AND ( newer.measured_at > r.measured_at OR (newer.measured_at = r.measured_at AND newer.id > r.id) ) )
AND ( r.measured_at < #{cursorMeasuredAt} OR (r.measured_at = #{cursorMeasuredAt} AND r.id < #{cursorId}) )
ORDER BY r.measured_at DESC, r.id DESC LIMIT #{limit}

SELECT id, user_id, metric_type, metric_value, unit, record_date, measured_at, created_at, updated_at FROM body_metric_record WHERE user_id = #{userId} AND metric_type = #{metricType}
AND ( measured_at < #{cursorMeasuredAt} OR (measured_at = #{cursorMeasuredAt} AND id < #{cursorId}) )
ORDER BY measured_at DESC, id DESC LIMIT #{limit}
